#include<bits/stdc++.h>
using namespace std;
struct node{
	int b,c;
}d[101];
char a[101];
int main()
{
	int i,j,n;
	scanf("%d",&n);
	for(i=1;i<=n;i++)
	{
		scanf("%s",a);
		scanf("%d%d\n",&d[i].b,&d[i].c);
		d[i].b+=1;
		d[i].c=d[i].c+d[i].c/5;
		if(d[i].c>600)
		{
			d[i].c=600;
		}
		printf("%s",a);
		printf(" %d %d\n",d[i].b,d[i].c);
	}
	return 0;
}
